{
  "terms": [
    {
      "term": "Generation",
      "simpleDefinition": "The process of converting energy sources like wind, sun, or fuel into electrical energy.",
      "anchor": "The starting point of the electrical supply chain.",
      "misconception": "Thinking electricity is 'created' from nothing; it is always converted from another energy source."
    },
    {
      "term": "Transmission",
      "simpleDefinition": "The bulk movement of electricity over long distances at very high voltages to reduce energy loss.",
      "anchor": "The 'motorway' system of the electrical grid.",
      "misconception": "Confusing transmission with distribution, which happens at lower voltages for local use."
    },
    {
      "term": "Transmission Voltages",
      "simpleDefinition": "The specific high-pressure levels used on the UK National Grid: 400 kV, 275 kV, and 132 kV.",
      "anchor": "The 'Big Three' high voltages: 400, 275, and 132.",
      "misconception": "Believing that 11 kV or 33 kV are transmission voltages; these are actually distribution voltages."
    },
    {
      "term": "Micro-generation",
      "simpleDefinition": "Small-scale production of electricity, often by individual homes or businesses using renewables.",
      "anchor": "Local power like domestic solar panels.",
      "misconception": "Thinking micro-generation is too small to be considered a valid part of the national distribution network."
    },
    {
      "term": "Photovoltaic (PV)",
      "simpleDefinition": "A method of generating electricity directly from sunlight using solar cells.",
      "anchor": "Solar panels on a roof.",
      "misconception": "Thinking PV panels require heat to work; they actually only require light."
    },
    {
      "term": "Biomass",
      "simpleDefinition": "Generating electricity by burning organic materials, such as wood pellets or plant waste.",
      "anchor": "Fuel from living or recently living organisms.",
      "misconception": "Confusing biomass with fossil fuels like coal or oil."
    }
  ],
  "anchorPhrases": [
    "Transmission happens at 400 kV, 275 kV, and 132 kV.",
    "Generation is the first stage of the supply chain.",
    "High voltage is used for transmission to minimize energy loss over distance.",
    "Renewable generation includes wind, wave, hydro, and photovoltaic."
  ],
  "misconceptionTargets": [
    "Mistaking 11 kV or 33 kV for transmission voltages.",
    "Assuming all generation methods involve burning fossil fuels.",
    "Using the terms 'transmission' and 'distribution' interchangeably.",
    "Believing that transmission occurs at standard domestic voltages like 230 V."
  ]
}

